import json,sys
d=json.load(sys.stdin)

# Check all nested configs
def find_keys(obj, target_keys, path=''):
    if isinstance(obj, dict):
        for k,v in obj.items():
            new_path = f'{path}.{k}' if path else k
            if any(tk in k.lower() for tk in ['linkfox','echotik','1688','sorftime','api','key','token']):
                print(f'{new_path}: {str(v)[:200]}')
            find_keys(v, target_keys, new_path)
    elif isinstance(obj, list):
        for i,item in enumerate(obj):
            find_keys(item, target_keys, f'{path}[{i}]')

find_keys(d, [])
